mapper.select:
SELECT a.id, a.apply_no, a.patient_id, p.patient_name, p.patient_no, p.bed_no, a.ward_id, w.ward_name, a.person_id, ap.person_name, ap.id_card, ap.phone, ap.relation, a.apply_reason, a.expected_start_date, a.expected_end_date, a.apply_status, a.audit_user_name, a.audit_time, a.audit_remark, a.invalid_reason, a.invalid_time, a.apply_time FROM accompany_apply a LEFT JOIN patient p ON a.patient_id = p.id LEFT JOIN ward w ON a.ward_id = w.id LEFT JOIN accompany_person ap ON a.person_id = ap.id WHERE a.deleted = 0
AND a.ward_id = #{wardId}
AND a.apply_status = #{applyStatus}
AND p.patient_name LIKE CONCAT('%', #{patientName}, '%')
AND ap.person_name LIKE CONCAT('%', #{personName}, '%')
ORDER BY a.apply_time DESC
